DECLARE

  V_SQL_FORMULA_101 VARCHAR2(10000);
  V_SQL_FORMULA_102 VARCHAR2(10000);
  V_SQL_FORMULA_103 VARCHAR2(10000);
  V_SQL_FORMULA_104 VARCHAR2(10000);
  V_SQL_FORMULA_105 VARCHAR2(10000);
  V_SQL_FORMULA_106 VARCHAR2(10000);
  V_SQL_FORMULA_107 VARCHAR2(10000);
  V_SQL_FORMULA_108 VARCHAR2(10000);
  V_SQL_FORMULA_109 VARCHAR2(10000);
  V_SQL_FORMULA_110 VARCHAR2(10000);
  V_SQL_FORMULA_111 VARCHAR2(10000);
  V_SQL_FORMULA_112 VARCHAR2(10000);
  V_SQL_FORMULA_113 VARCHAR2(10000);
  V_SQL_FORMULA_DETALHE_101 VARCHAR2(10000);
  V_SQL_FORMULA_DETALHE_102 VARCHAR2(10000);
  V_SQL_FORMULA_DETALHE_103 VARCHAR2(10000);
  V_SQL_FORMULA_DETALHE_104 VARCHAR2(10000);
  V_SQL_FORMULA_DETALHE_105 VARCHAR2(10000);
  V_SQL_FORMULA_DETALHE_106 VARCHAR2(10000);
  V_SQL_FORMULA_DETALHE_107 VARCHAR2(10000);
  V_SQL_FORMULA_DETALHE_108 VARCHAR2(10000);
  V_SQL_FORMULA_DETALHE_109 VARCHAR2(10000);
  V_SQL_FORMULA_DETALHE_110 VARCHAR2(10000);
  V_SQL_FORMULA_DETALHE_111 VARCHAR2(10000);
  V_SQL_FORMULA_DETALHE_112 VARCHAR2(10000);
  V_SQL_FORMULA_DETALHE_113 VARCHAR2(10000);

BEGIN

  V_SQL_FORMULA_101 := 'SELECT CASE WHEN IP.TOTAL / SUM(I.QT * I.PVENDA) * 100 <= :PARAM THEN ''TRUE'' ELSE ''FALSE'' END PODE_SEGUIR, :PARAM PARAMETRO, IP.TOTAL / SUM(I.QT * I.PVENDA) * 100 VALOR_OBTIDO FROM PCPEDI I, (SELECT NUMPED, SUM(QT * PVENDA) TOTAL FROM PCPEDI WHERE NUMPED = :NUMPED AND CODPROMOCAOMED = :CODPROMOCAOMED GROUP BY NUMPED) IP WHERE I.NUMPED = IP.NUMPED AND I.NUMPED = :NUMPED GROUP BY IP.TOTAL';
  V_SQL_FORMULA_102 := 'SELECT CASE WHEN (IP.TOTAL / COUNT(DISTINCT I.CODPROD) * 100) >= :PARAM THEN ''TRUE'' ELSE ''FALSE'' END PODE_SEGUIR, :PARAM PARAMETRO, (IP.TOTAL / COUNT(DISTINCT I.CODPROD) * 100) VALOR_OBTIDO FROM PCPEDI I, (SELECT P.NUMPED, COUNT(DISTINCT P.CODPROD) TOTAL FROM PCPEDI P, PCDESCONTO D WHERE P.CODPROMOCAOMED = D.CODPROMOCAOMED AND P.CODDESCONTO = D.CODDESCONTO AND P.NUMPED = :NUMPED AND P.CODPROMOCAOMED = :CODPROMOCAOMED AND D.OBRIGATORIOPARCIALMED = ''S'' GROUP BY P.NUMPED) IP WHERE I.NUMPED = IP.NUMPED AND I.NUMPED = :NUMPED AND I.CODPROMOCAOMED = :CODPROMOCAOMED GROUP BY IP.TOTAL';
  V_SQL_FORMULA_103 := 'SELECT CASE WHEN COUNT(DISTINCT CODPROD) >= :PARAM THEN ''TRUE'' ELSE ''FALSE'' END PODE_SEGUIR, :PARAM PARAMETRO, COUNT(DISTINCT CODPROD) VALOR_OBTIDO FROM PCPEDI WHERE NUMPED = :NUMPED';
  V_SQL_FORMULA_104 := 'SELECT CASE WHEN COUNT(1) >= :PARAM THEN ''TRUE'' ELSE ''FALSE'' END PODE_SEGUIR, :PARAM PARAMETRO, COUNT(1) VALOR_OBTIDO FROM PCPEDI WHERE NUMPED = :NUMPED AND CODPROMOCAOMED = :CODPROMOCAOMED';
  V_SQL_FORMULA_105 := 'SELECT CASE WHEN (SELECT COUNT(1) FROM (SELECT CODPROMOCAOMED FROM PCPEDI I WHERE NUMPED = :NUMPED GROUP BY CODPROMOCAOMED) A) = 1 THEN ''TRUE'' ELSE ''FALSE'' END PODE_SEGUIR, NULL PARAMETRO, (SELECT COUNT(1) FROM (SELECT CODPROMOCAOMED FROM PCPEDI I WHERE NUMPED = :NUMPED GROUP BY CODPROMOCAOMED) A) VALOR_OBTIDO FROM DUAL';
  V_SQL_FORMULA_106 := 'SELECT CASE WHEN SUM(I.QT * I.PVENDA) <= :PARAM THEN ''TRUE'' ELSE ''FALSE'' END PODE_SEGUIR, :PARAM PARAMETRO, SUM(I.QT * I.PVENDA) VALOR_OBTIDO FROM PCPEDI I WHERE I.NUMPED = :NUMPED AND I.CODPROMOCAOMED = :CODPROMOCAOMED';
  V_SQL_FORMULA_107 := 'SELECT CASE WHEN SUM(I.QT * I.PVENDA) >= :PARAM THEN ''TRUE'' ELSE ''FALSE'' END PODE_SEGUIR, :PARAM PARAMETRO, SUM(I.QT * I.PVENDA) VALOR_OBTIDO FROM PCPEDI I WHERE I.NUMPED = :NUMPED AND I.CODPROMOCAOMED = :CODPROMOCAOMED';
  V_SQL_FORMULA_108 := 'SELECT CASE WHEN SUM(I.QT * I.PVENDA) >= :PARAM THEN ''TRUE'' ELSE ''FALSE'' END PODE_SEGUIR, :PARAM, SUM(I.QT * I.PVENDA) VALOR_OBTIDO FROM PCPEDI I WHERE NUMPED = :NUMPED';
  V_SQL_FORMULA_109 := 'SELECT CASE WHEN SUM(CASE WHEN A.PODE_SEGUIR = ''FALSE'' THEN 1 ELSE 0 END) > 0 THEN ''FALSE'' ELSE ''TRUE'' END PODE_SEGUIR, (CASE WHEN SUM(CASE WHEN A.PODE_SEGUIR = ''FALSE'' THEN 1 ELSE 0 END) > 0 THEN SUM(CASE WHEN A.PODE_SEGUIR = ''FALSE'' THEN A.PARAMETRO END) ELSE SUM(CASE WHEN A.PODE_SEGUIR = ''TRUE'' THEN A.PARAMETRO END) END) PARAMETRO, (CASE WHEN SUM(CASE WHEN A.PODE_SEGUIR = ''FALSE'' THEN 1 ELSE 0 END) > 0 THEN SUM(CASE WHEN A.PODE_SEGUIR = ''FALSE'' THEN A.VALOR_OBTIDO END) ELSE SUM(CASE WHEN A.PODE_SEGUIR = ''TRUE'' THEN A.VALOR_OBTIDO END) END) VALOR_OBTIDO FROM (SELECT CASE WHEN COUNT(DISTINCT(I.CODPROD)) >= B.QTMINMIXFORNECEDORMED THEN ''TRUE'' ELSE ''FALSE'' END PODE_SEGUIR, B.CODFORNEC, B.QTMINMIXFORNECEDORMED PARAMETRO, COUNT(DISTINCT(I.CODPROD)) VALOR_OBTIDO FROM PCPEDI I, PCPRODUT P, (SELECT CODFORNEC, SUM(QTMINMIXFORNECEDORMED) QTMINMIXFORNECEDORMED FROM (SELECT DISTINCT P.CODPROD, P.CODFORNEC, NVL(D.QTMINMIXFORNECEDORMED, 0) QTMINMIXFORNECEDORMED FROM PCPEDI I, PCDESCONTO D, PCPRODUT P WHERE I.CODPROMOCAOMED = D.CODPROMOCAOMED AND I.CODDESCONTO = D.CODDESCONTO AND I.CODPROD = P.CODPROD AND I.NUMPED = :NUMPED AND I.CODPROMOCAOMED = :CODPROMOCAOMED) GROUP BY CODFORNEC) B WHERE P.CODFORNEC = B.CODFORNEC AND I.CODPROD = P.CODPROD AND I.NUMPED = :NUMPED AND B.QTMINMIXFORNECEDORMED > 0 GROUP BY B.CODFORNEC, B.QTMINMIXFORNECEDORMED) A';
  V_SQL_FORMULA_110 := 'SELECT CASE WHEN SUM(CASE WHEN A.PODE_SEGUIR = ''FALSE'' THEN 1 ELSE 0 END) > 0 THEN ''FALSE'' ELSE ''TRUE'' END PODE_SEGUIR, (CASE WHEN SUM(CASE WHEN A.PODE_SEGUIR = ''FALSE'' THEN 1 ELSE 0 END) > 0 THEN SUM(CASE WHEN A.PODE_SEGUIR = ''FALSE'' THEN A.PARAMETRO END) ELSE SUM(CASE WHEN A.PODE_SEGUIR = ''TRUE'' THEN A.PARAMETRO END) END) PARAMETRO, (CASE WHEN SUM(CASE WHEN A.PODE_SEGUIR = ''FALSE'' THEN 1 ELSE 0 END) > 0 THEN SUM(CASE WHEN A.PODE_SEGUIR = ''FALSE'' THEN A.VALOR_OBTIDO END) ELSE SUM(CASE WHEN A.PODE_SEGUIR = ''TRUE'' THEN A.VALOR_OBTIDO END) END) VALOR_OBTIDO FROM (SELECT CASE WHEN COUNT(DISTINCT(I.CODPROD)) >= B.QTMINMIXFORNECEDORMED THEN ''TRUE'' ELSE ''FALSE'' END PODE_SEGUIR, B.CODFORNEC, B.QTMINMIXFORNECEDORMED PARAMETRO, COUNT(DISTINCT(I.CODPROD)) VALOR_OBTIDO FROM PCPEDI I, PCPRODUT P, (SELECT P.CODFORNEC, MAX(NVL(D.QTMINMIXFORNECEDORMED, 0)) QTMINMIXFORNECEDORMED FROM PCPEDI I, PCDESCONTO D, PCPRODUT P WHERE I.CODPROMOCAOMED = D.CODPROMOCAOMED AND I.CODDESCONTO = D.CODDESCONTO AND I.CODPROD = P.CODPROD AND I.NUMPED = :NUMPED AND I.CODPROMOCAOMED = :CODPROMOCAOMED GROUP BY P.CODFORNEC) B WHERE P.CODFORNEC = B.CODFORNEC AND I.CODPROD = P.CODPROD AND I.NUMPED = :NUMPED AND B.QTMINMIXFORNECEDORMED > 0 GROUP BY B.CODFORNEC, B.QTMINMIXFORNECEDORMED) A';
  V_SQL_FORMULA_111 := 'SELECT CASE WHEN IP.TOTAL / SUM(I.QT * I.PVENDA) * 100 <= :PARAM THEN ''TRUE'' ELSE ''FALSE'' END PODE_SEGUIR, :PARAM PARAMETRO, IP.TOTAL / SUM(I.QT * I.PVENDA) * 100 VALOR_OBTIDO FROM PCPEDI I, (SELECT NUMPED, SUM(QT * PVENDA) TOTAL FROM PCPEDI WHERE NUMPED = :NUMPED AND CODDESCONTO = :CODDESCONTO GROUP BY NUMPED) IP WHERE I.NUMPED = IP.NUMPED AND I.NUMPED = :NUMPED GROUP BY IP.TOTAL';
  V_SQL_FORMULA_112 := 'SELECT CASE WHEN SUM(I.QT * I.PVENDA) <= :PARAM THEN ''TRUE'' ELSE ''FALSE'' END PODE_SEGUIR, :PARAM PARAMETRO, SUM(I.QT * I.PVENDA) VALOR_OBTIDO FROM PCPEDI I WHERE I.NUMPED = :NUMPED AND I.CODDESCONTO = :CODDESCONTO';
  V_SQL_FORMULA_113 := 'SELECT CASE WHEN SUM(I.QT * I.PVENDA) >= :PARAM THEN ''TRUE'' ELSE ''FALSE'' END PODE_SEGUIR, :PARAM PARAMETRO, SUM(I.QT * I.PVENDA) VALOR_OBTIDO FROM PCPEDI I WHERE I.NUMPED = :NUMPED AND I.CODDESCONTO = :CODDESCONTO';

  V_SQL_FORMULA_DETALHE_101 := 'SELECT A.REQUISITO_STATUS, A.REQUISITO_VALOR_ALVO, A.REQUISITO_VALOR_OBTIDO, NULL AS NIVEL_CODIGO, NULL AS NIVEL_DESCRICAO, NULL AS NIVEL_STATUS, NULL AS NIVEL_VALOR_ALVO, NULL AS NIVEL_VALOR_OBTIDO, CASE WHEN A.REQUISITO_STATUS = ''F'' THEN ''Adicionar itens que não estejam vinculados à promoção ou reduzir a quantidade de itens vinculados à promoção.'' ELSE NULL END AS TEXTO_AJUDA FROM (SELECT CASE WHEN IP.TOTAL / SUM(I.QT * I.PVENDA) * 100 <= :PARAM THEN ''T'' ELSE ''F'' END AS REQUISITO_STATUS, :PARAM AS REQUISITO_VALOR_ALVO, (IP.TOTAL / SUM(I.QT * I.PVENDA) * 100) AS REQUISITO_VALOR_OBTIDO FROM PCPEDI I, (SELECT NUMPED, SUM(QT * PVENDA) TOTAL FROM PCPEDI WHERE NUMPED = :NUMPED AND CODPROMOCAOMED = :CODPROMOCAOMED GROUP BY NUMPED) IP WHERE I.NUMPED = IP.NUMPED AND I.NUMPED = :NUMPED GROUP BY IP.TOTAL) A';
  V_SQL_FORMULA_DETALHE_102 := 'SELECT A.REQUISITO_STATUS, A.REQUISITO_VALOR_ALVO, A.REQUISITO_VALOR_OBTIDO, NULL AS NIVEL_CODIGO, NULL AS NIVEL_DESCRICAO, NULL AS NIVEL_STATUS, NULL AS NIVEL_VALOR_ALVO, NULL AS NIVEL_VALOR_OBTIDO, CASE WHEN A.REQUISITO_STATUS = ''F'' THEN ''Adicionar mais itens vinculados à promoção no pedido.'' ELSE NULL END AS TEXTO_AJUDA FROM (SELECT CASE WHEN (IP.TOTAL / COUNT(DISTINCT I.CODPROD) * 100) >= :PARAM THEN ''T'' ELSE ''F'' END AS REQUISITO_STATUS, :PARAM AS REQUISITO_VALOR_ALVO, (IP.TOTAL / COUNT(DISTINCT I.CODPROD) * 100) AS REQUISITO_VALOR_OBTIDO FROM PCPEDI I, (SELECT P.NUMPED, COUNT(DISTINCT P.CODPROD) TOTAL FROM PCPEDI P, PCDESCONTO D WHERE P.CODPROMOCAOMED = D.CODPROMOCAOMED AND P.CODDESCONTO = D.CODDESCONTO AND P.NUMPED = :NUMPED AND P.CODPROMOCAOMED = :CODPROMOCAOMED AND D.OBRIGATORIOPARCIALMED = ''S'' GROUP BY P.NUMPED) IP WHERE I.NUMPED = IP.NUMPED AND I.NUMPED = :NUMPED AND I.CODPROMOCAOMED = :CODPROMOCAOMED GROUP BY IP.TOTAL) A';
  V_SQL_FORMULA_DETALHE_103 := 'SELECT A.REQUISITO_STATUS, A.REQUISITO_VALOR_ALVO, A.REQUISITO_VALOR_OBTIDO, NULL AS NIVEL_CODIGO, NULL AS NIVEL_DESCRICAO, NULL AS NIVEL_STATUS, NULL AS NIVEL_VALOR_ALVO, NULL AS NIVEL_VALOR_OBTIDO, CASE WHEN A.REQUISITO_STATUS = ''F'' THEN CASE WHEN (A.REQUISITO_VALOR_ALVO - A.REQUISITO_VALOR_OBTIDO) = 1 THEN ''Adicionar 1 item distinto ao pedido.'' ELSE ''Adicionar '' || TO_CHAR(A.REQUISITO_VALOR_ALVO - A.REQUISITO_VALOR_OBTIDO) || '' itens distintos ao pedido.'' END ELSE NULL END AS TEXTO_AJUDA FROM (SELECT CASE WHEN COUNT(DISTINCT CODPROD) >= :PARAM THEN ''T'' ELSE ''F'' END AS REQUISITO_STATUS, :PARAM AS REQUISITO_VALOR_ALVO, COUNT(DISTINCT CODPROD) AS REQUISITO_VALOR_OBTIDO FROM PCPEDI WHERE NUMPED = :NUMPED) A';
  V_SQL_FORMULA_DETALHE_104 := 'SELECT A.REQUISITO_STATUS, A.REQUISITO_VALOR_ALVO, A.REQUISITO_VALOR_OBTIDO, NULL AS NIVEL_CODIGO, NULL AS NIVEL_DESCRICAO, NULL AS NIVEL_STATUS, NULL AS NIVEL_VALOR_ALVO, NULL AS NIVEL_VALOR_OBTIDO, CASE WHEN A.REQUISITO_STATUS = ''F'' THEN CASE WHEN (A.REQUISITO_VALOR_ALVO - A.REQUISITO_VALOR_OBTIDO) = 1 THEN ''Adicionar 1 item da promoção ao pedido.'' ELSE ''Adicionar '' || TO_CHAR(A.REQUISITO_VALOR_ALVO - A.REQUISITO_VALOR_OBTIDO) || '' itens da promoção ao pedido.'' END ELSE NULL END AS TEXTO_AJUDA FROM (SELECT CASE WHEN COUNT(1) >= :PARAM THEN ''T'' ELSE ''F'' END AS REQUISITO_STATUS, :PARAM AS REQUISITO_VALOR_ALVO, COUNT(1) AS REQUISITO_VALOR_OBTIDO FROM PCPEDI WHERE NUMPED = :NUMPED AND CODPROMOCAOMED = :CODPROMOCAOMED) A';
  V_SQL_FORMULA_DETALHE_105 := 'SELECT B.REQUISITO_STATUS, B.REQUISITO_VALOR_ALVO, B.REQUISITO_VALOR_OBTIDO, NULL AS NIVEL_CODIGO, NULL AS NIVEL_DESCRICAO, NULL AS NIVEL_STATUS, NULL AS NIVEL_VALOR_ALVO, NULL AS NIVEL_VALOR_OBTIDO, CASE WHEN B.REQUISITO_STATUS = ''F'' THEN ''Remover as demais promoções vinculadas ao pedido, mantendo apenas esta.'' ELSE NULL END AS TEXTO_AJUDA FROM (SELECT CASE WHEN (SELECT COUNT(1) FROM (SELECT CODPROMOCAOMED FROM PCPEDI I WHERE NUMPED = :NUMPED GROUP BY CODPROMOCAOMED) A) = 1 THEN ''T'' ELSE ''F'' END AS REQUISITO_STATUS, 1 AS REQUISITO_VALOR_ALVO, (SELECT COUNT(1) FROM (SELECT CODPROMOCAOMED FROM PCPEDI I WHERE NUMPED = :NUMPED GROUP BY CODPROMOCAOMED) A) AS REQUISITO_VALOR_OBTIDO FROM DUAL) B';
  V_SQL_FORMULA_DETALHE_106 := 'SELECT A.REQUISITO_STATUS, A.REQUISITO_VALOR_ALVO, A.REQUISITO_VALOR_OBTIDO, NULL AS NIVEL_CODIGO, NULL AS NIVEL_DESCRICAO, NULL AS NIVEL_STATUS, NULL AS NIVEL_VALOR_ALVO, NULL AS NIVEL_VALOR_OBTIDO, CASE WHEN A.REQUISITO_STATUS = ''F'' THEN ''Reduzir o valor do pedido em '' || TRIM(TO_CHAR(A.REQUISITO_VALOR_OBTIDO - A.REQUISITO_VALOR_ALVO, ''999G999D99'', ''NLS_NUMERIC_CHARACTERS = '''',.'''''')) || ''.'' ELSE NULL END AS TEXTO_AJUDA FROM (SELECT CASE WHEN SUM(I.QT * I.PVENDA) <= :PARAM THEN ''T'' ELSE ''F'' END AS REQUISITO_STATUS, :PARAM AS REQUISITO_VALOR_ALVO, SUM(I.QT * I.PVENDA) REQUISITO_VALOR_OBTIDO FROM PCPEDI I WHERE I.NUMPED = :NUMPED AND I.CODPROMOCAOMED = :CODPROMOCAOMED) A';
  V_SQL_FORMULA_DETALHE_107 := 'SELECT A.REQUISITO_STATUS, A.REQUISITO_VALOR_ALVO, A.REQUISITO_VALOR_OBTIDO, NULL AS NIVEL_CODIGO, NULL AS NIVEL_DESCRICAO, NULL AS NIVEL_STATUS, NULL AS NIVEL_VALOR_ALVO, NULL AS NIVEL_VALOR_OBTIDO, CASE WHEN A.REQUISITO_STATUS = ''F'' THEN ''Adicionar o valor de '' || TRIM(TO_CHAR(A.REQUISITO_VALOR_ALVO - A.REQUISITO_VALOR_OBTIDO, ''999G999D99'', ''NLS_NUMERIC_CHARACTERS = '''',.'''''')) || '' ao pedido para que ele possa ser gerado usando esta promoção.'' ELSE NULL END AS TEXTO_AJUDA FROM (SELECT CASE WHEN SUM(I.QT * I.PVENDA) >= :PARAM THEN ''T'' ELSE ''F'' END AS REQUISITO_STATUS, :PARAM AS REQUISITO_VALOR_ALVO, SUM(I.QT * I.PVENDA) REQUISITO_VALOR_OBTIDO FROM PCPEDI I WHERE I.NUMPED = :NUMPED AND I.CODPROMOCAOMED = :CODPROMOCAOMED) A';
  V_SQL_FORMULA_DETALHE_108 := 'SELECT A.REQUISITO_STATUS, A.REQUISITO_VALOR_ALVO, A.REQUISITO_VALOR_OBTIDO, NULL AS NIVEL_CODIGO, NULL AS NIVEL_DESCRICAO, NULL AS NIVEL_STATUS, NULL AS NIVEL_VALOR_ALVO, NULL AS NIVEL_VALOR_OBTIDO, CASE WHEN A.REQUISITO_STATUS = ''F'' THEN ''Adicionar o valor faltante de '' || TRIM(TO_CHAR(A.REQUISITO_VALOR_ALVO - A.REQUISITO_VALOR_OBTIDO, ''999G999D99'', ''NLS_NUMERIC_CHARACTERS = '''',.'''''')) || '' para gerar o pedido.'' ELSE NULL END AS TEXTO_AJUDA FROM (SELECT CASE WHEN SUM(I.QT * I.PVENDA) >= :PARAM THEN ''T'' ELSE ''F'' END AS REQUISITO_STATUS, :PARAM AS REQUISITO_VALOR_ALVO, SUM(I.QT * I.PVENDA) REQUISITO_VALOR_OBTIDO FROM PCPEDI I WHERE NUMPED = :NUMPED) A';
  V_SQL_FORMULA_DETALHE_109 := 'SELECT NULL AS REQUISITO_STATUS, NULL AS REQUISITO_VALOR_ALVO, NULL AS REQUISITO_VALOR_OBTIDO, B.CODFORNEC AS NIVEL_CODIGO, B.FORNECEDOR AS NIVEL_DESCRICAO, B.STATUS AS NIVEL_STATUS, B.VALOR_ALVO AS NIVEL_VALOR_ALVO, B.VALOR_OBTIDO AS NIVEL_VALOR_OBTIDO, CASE WHEN B.STATUS = ''F'' THEN CASE WHEN (B.VALOR_ALVO - B.VALOR_OBTIDO) = 1 THEN ''Adicionar 1 item do fornecedor ao pedido.'' ELSE ''Adicionar '' || TO_CHAR(B.VALOR_ALVO - B.VALOR_OBTIDO) || '' itens do fornecedor ao pedido.'' END ELSE NULL END AS TEXTO_AJUDA FROM (SELECT CASE WHEN COUNT(DISTINCT(I.CODPROD)) >= A.QTMINMIXFORNECEDORMED THEN ''T'' ELSE ''F'' END AS STATUS, A.QTMINMIXFORNECEDORMED AS VALOR_ALVO, COUNT(DISTINCT(I.CODPROD)) AS VALOR_OBTIDO, F.CODFORNEC, (''Fornecedor '' || TO_CHAR(F.CODFORNEC) || '' - '' || F.FORNECEDOR) AS FORNECEDOR FROM PCPEDI I, PCPRODUT P, PCFORNEC F, (SELECT CODFORNEC, SUM(QTMINMIXFORNECEDORMED) QTMINMIXFORNECEDORMED FROM (SELECT DISTINCT P.CODPROD, P.CODFORNEC, NVL(D.QTMINMIXFORNECEDORMED, 0) QTMINMIXFORNECEDORMED FROM PCPEDI I, PCDESCONTO D, PCPRODUT P WHERE I.CODPROMOCAOMED = D.CODPROMOCAOMED AND I.CODDESCONTO = D.CODDESCONTO AND I.CODPROD = P.CODPROD AND I.NUMPED = :NUMPED AND I.CODPROMOCAOMED = :CODPROMOCAOMED) GROUP BY CODFORNEC) A WHERE P.CODFORNEC = A.CODFORNEC AND P.CODFORNEC = F.CODFORNEC AND I.CODPROD = P.CODPROD AND I.NUMPED = :NUMPED AND A.QTMINMIXFORNECEDORMED > 0 GROUP BY A.QTMINMIXFORNECEDORMED, F.CODFORNEC, F.FORNECEDOR) B';
  V_SQL_FORMULA_DETALHE_110 := 'SELECT NULL AS REQUISITO_STATUS, NULL AS REQUISITO_VALOR_ALVO, NULL AS REQUISITO_VALOR_OBTIDO, B.CODFORNEC AS NIVEL_CODIGO, B.FORNECEDOR AS NIVEL_DESCRICAO, B.STATUS AS NIVEL_STATUS, B.VALOR_ALVO AS NIVEL_VALOR_ALVO, B.VALOR_OBTIDO AS NIVEL_VALOR_OBTIDO, CASE WHEN B.STATUS = ''F'' THEN CASE WHEN (B.VALOR_ALVO - B.VALOR_OBTIDO) = 1 THEN ''Adicionar 1 item do fornecedor ao pedido.'' ELSE ''Adicionar '' || TO_CHAR(B.VALOR_ALVO - B.VALOR_OBTIDO) || '' itens do fornecedor ao pedido.'' END ELSE NULL END AS TEXTO_AJUDA FROM (SELECT CASE WHEN COUNT(DISTINCT(I.CODPROD)) >= A.QTMINMIXFORNECEDORMED THEN ''T'' ELSE ''F'' END AS STATUS, A.QTMINMIXFORNECEDORMED AS VALOR_ALVO, COUNT(DISTINCT(I.CODPROD)) AS VALOR_OBTIDO, F.CODFORNEC, (''Fornecedor '' || TO_CHAR(F.CODFORNEC) || '' - '' || F.FORNECEDOR) AS FORNECEDOR FROM PCPEDI I, PCPRODUT P, PCFORNEC F, (SELECT P.CODFORNEC, MAX(NVL(D.QTMINMIXFORNECEDORMED, 0)) QTMINMIXFORNECEDORMED FROM PCPEDI I, PCDESCONTO D, PCPRODUT P WHERE I.CODPROMOCAOMED = D.CODPROMOCAOMED AND I.CODDESCONTO = D.CODDESCONTO AND I.CODPROD = P.CODPROD AND I.NUMPED = :NUMPED AND I.CODPROMOCAOMED = :CODPROMOCAOMED GROUP BY P.CODFORNEC) A WHERE P.CODFORNEC = A.CODFORNEC AND P.CODFORNEC = F.CODFORNEC AND I.CODPROD = P.CODPROD AND I.NUMPED = :NUMPED AND A.QTMINMIXFORNECEDORMED > 0 GROUP BY A.QTMINMIXFORNECEDORMED, F.CODFORNEC, F.FORNECEDOR) B';
  V_SQL_FORMULA_DETALHE_111 := 'SELECT A.REQUISITO_STATUS, A.REQUISITO_VALOR_ALVO, A.REQUISITO_VALOR_OBTIDO, NULL AS NIVEL_CODIGO, NULL AS NIVEL_DESCRICAO, NULL AS NIVEL_STATUS, NULL AS NIVEL_VALOR_ALVO, NULL AS NIVEL_VALOR_OBTIDO, CASE WHEN A.REQUISITO_STATUS = ''F'' THEN ''Adicionar itens que não estejam vinculados à promoção ou reduzir a quantidade de itens vinculados à promoção.'' ELSE NULL END AS TEXTO_AJUDA FROM (SELECT CASE WHEN IP.TOTAL / SUM(I.QT * I.PVENDA) * 100 <= :PARAM THEN ''T'' ELSE ''F'' END AS REQUISITO_STATUS, :PARAM AS REQUISITO_VALOR_ALVO, (IP.TOTAL / SUM(I.QT * I.PVENDA) * 100) AS REQUISITO_VALOR_OBTIDO FROM PCPEDI I, (SELECT NUMPED, SUM(QT * PVENDA) TOTAL FROM PCPEDI WHERE NUMPED = :NUMPED AND CODDESCONTO = :CODDESCONTO GROUP BY NUMPED) IP WHERE I.NUMPED = IP.NUMPED AND I.NUMPED = :NUMPED GROUP BY IP.TOTAL) A';
  V_SQL_FORMULA_DETALHE_112 := 'SELECT A.REQUISITO_STATUS, A.REQUISITO_VALOR_ALVO, A.REQUISITO_VALOR_OBTIDO, NULL AS NIVEL_CODIGO, NULL AS NIVEL_DESCRICAO, NULL AS NIVEL_STATUS, NULL AS NIVEL_VALOR_ALVO, NULL AS NIVEL_VALOR_OBTIDO, CASE WHEN A.REQUISITO_STATUS = ''F'' THEN ''Reduzir o valor do pedido em '' || TRIM(TO_CHAR(A.REQUISITO_VALOR_OBTIDO - A.REQUISITO_VALOR_ALVO, ''999G999D99'', ''NLS_NUMERIC_CHARACTERS = '''',.'''''')) || ''.'' ELSE NULL END AS TEXTO_AJUDA FROM (SELECT CASE WHEN SUM(I.QT * I.PVENDA) <= :PARAM THEN ''T'' ELSE ''F'' END AS REQUISITO_STATUS, :PARAM AS REQUISITO_VALOR_ALVO, SUM(I.QT * I.PVENDA) REQUISITO_VALOR_OBTIDO FROM PCPEDI I WHERE I.NUMPED = :NUMPED AND I.CODDESCONTO = :CODDESCONTO) A';
  V_SQL_FORMULA_DETALHE_113 := 'SELECT A.REQUISITO_STATUS, A.REQUISITO_VALOR_ALVO, A.REQUISITO_VALOR_OBTIDO, NULL AS NIVEL_CODIGO, NULL AS NIVEL_DESCRICAO, NULL AS NIVEL_STATUS, NULL AS NIVEL_VALOR_ALVO, NULL AS NIVEL_VALOR_OBTIDO, CASE WHEN A.REQUISITO_STATUS = ''F'' THEN ''Adicionar o valor de '' || TRIM(TO_CHAR(A.REQUISITO_VALOR_ALVO - A.REQUISITO_VALOR_OBTIDO, ''999G999D99'', ''NLS_NUMERIC_CHARACTERS = '''',.'''''')) || '' ao pedido para que ele possa ser gerado usando esta promoção.'' ELSE NULL END AS TEXTO_AJUDA FROM (SELECT CASE WHEN SUM(I.QT * I.PVENDA) >= :PARAM THEN ''T'' ELSE ''F'' END AS REQUISITO_STATUS, :PARAM AS REQUISITO_VALOR_ALVO, SUM(I.QT * I.PVENDA) REQUISITO_VALOR_OBTIDO FROM PCPEDI I WHERE I.NUMPED = :NUMPED AND I.CODDESCONTO = :CODDESCONTO) A';

  DELETE PCFILTROAVANCADOCONFIG WHERE CODCONFIG IN (69, 88, 89, 90, 91, 92, 93, 94, 95, 99);

  MERGE INTO PCFILTROAVANCADOCONFIG tgt
  USING (
    SELECT 1 AS CODCONFIG
         , 'Produto' AS GRUPO
         , 'PCPRODUT' AS TABELA
         , 'CODPROD'AS CAMPO
         , 'NUMBER' AS TIPOCAMPO
         , 'CODPROD' AS NOMEPARAMETRO
         , NULL AS CHAVEMULTIPLA
         , 'Produto' AS NOMELIVRE
         , 'N' AS VISIVELFILTRO
         , 'S' AS VISIVELCONDICAO
         , 'S' AS VISIVELREGRAEXCECAO
         , 'PCPRODUT' AS TABELAPESQUISA
         , 'CODPROD' AS CAMPOPESQUISA
         , 'DESCRICAO' AS DESCRICAOPESQUISA
         , NULL AS CRITERIOPESQUISA
         , NULL AS ROTULOPESQUISA
         , '1' AS CODIGONIVEL
         , 'I' AS TIPOVALIDACAO
         , NULL AS FORMULASQL
         , 'NUMBER' AS TIPOPARAMETRO
         , NULL AS DETALHEFORMULASQL
      FROM DUAL
     UNION ALL
