  ) src
  ON (
    tgt.CODCONFIG = src.CODCONFIG
  )
  WHEN MATCHED THEN
    UPDATE SET tgt.GRUPO = src.GRUPO,
               tgt.TABELA = src.TABELA,
               tgt.CAMPO = src.CAMPO,
               tgt.TIPOCAMPO = src.TIPOCAMPO,
               tgt.NOMEPARAMETRO = src.NOMEPARAMETRO,
               tgt.CHAVEMULTIPLA = src.CHAVEMULTIPLA,
               tgt.TABELAPESQUISA = src.TABELAPESQUISA,
               tgt.CAMPOPESQUISA = src.CAMPOPESQUISA,
               tgt.DESCRICAOPESQUISA = src.DESCRICAOPESQUISA,
               tgt.CRITERIOPESQUISA = src.CRITERIOPESQUISA,
               tgt.ROTULOPESQUISA = src.ROTULOPESQUISA,
               tgt.CODIGONIVEL = src.CODIGONIVEL,
               tgt.TIPOVALIDACAO = src.TIPOVALIDACAO,
               tgt.FORMULASQL = src.FORMULASQL,
               tgt.TIPOPARAMETRO = src.TIPOPARAMETRO,
               tgt.DETALHEFORMULASQL = src.DETALHEFORMULASQL
    WHEN NOT MATCHED THEN
      INSERT (
        CODCONFIG,
        GRUPO,
        TABELA,
        CAMPO,
        TIPOCAMPO,
        NOMEPARAMETRO,
        CHAVEMULTIPLA,
        NOMELIVRE,
        VISIVELFILTRO,
        VISIVELCONDICAO,
        VISIVELREGRAEXCECAO,
        TABELAPESQUISA,
        CAMPOPESQUISA,
        DESCRICAOPESQUISA,
        CRITERIOPESQUISA,
        ROTULOPESQUISA,
        CODIGONIVEL,
        TIPOVALIDACAO,
        FORMULASQL,
        TIPOPARAMETRO,
        DETALHEFORMULASQL
      )
      VALUES (
        src.CODCONFIG,
        src.GRUPO,
        src.TABELA,
        src.CAMPO,
        src.TIPOCAMPO,
        src.NOMEPARAMETRO,
        src.CHAVEMULTIPLA,
        src.NOMELIVRE,
        src.VISIVELFILTRO,
        src.VISIVELCONDICAO,
        src.VISIVELREGRAEXCECAO,
        src.TABELAPESQUISA,
        src.CAMPOPESQUISA,
        src.DESCRICAOPESQUISA,
        src.CRITERIOPESQUISA,
        src.ROTULOPESQUISA,
        src.CODIGONIVEL,
        src.TIPOVALIDACAO,
        src.FORMULASQL,
        src.TIPOPARAMETRO,
        src.DETALHEFORMULASQL
      );

END;